-- ----------------------------
-- Table structure for adoption_agreement
-- ----------------------------
DROP TABLE IF EXISTS `adoption_agreement`;
CREATE TABLE `adoption_agreement`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `agreement_number` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '协议编号',
  `pet_id` bigint NOT NULL COMMENT '宠物ID',
  `adopter_id` bigint NOT NULL COMMENT '领养人ID',
  `organization_id` bigint NOT NULL COMMENT '机构ID',
  `adopter_id_card` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '领养人身份证号（协议留存，user表无此字段）',
  `adopter_address` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '领养人地址（协议留存，user表无此字段）',
  `adoption_fee` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '领养费用',
  `agreement_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '协议内容',
  `status` enum('draft','pending','signed','effective','expired','terminated') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'draft' COMMENT '协议状态',
  `sign_date` datetime NULL DEFAULT NULL COMMENT '签署日期',
  `effective_date` datetime NULL DEFAULT NULL COMMENT '生效日期',
  `expiry_date` datetime NULL DEFAULT NULL COMMENT '到期日期',
  `adopter_signature` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '领养人签名（支持base64图片）',
  `organization_signature` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '机构签名（支持base64图片）',
  `admin_signature` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '管理员签名（支持base64图片）',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `agreement_number`(`agreement_number` ASC) USING BTREE,
  INDEX `idx_pet_id`(`pet_id` ASC) USING BTREE,
  INDEX `idx_adopter_id`(`adopter_id` ASC) USING BTREE,
  INDEX `idx_organization_id`(`organization_id` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_adopter_status`(`adopter_id` ASC, `status` ASC) USING BTREE,
  INDEX `idx_organization_status`(`organization_id` ASC, `status` ASC) USING BTREE,
  INDEX `idx_status_effective`(`status` ASC, `effective_date` ASC) USING BTREE,
  INDEX `idx_expiry_date`(`expiry_date` ASC) USING BTREE,
  INDEX `idx_agr_status_create`(`status` ASC, `create_time` DESC) USING BTREE,
  CONSTRAINT `fk_agreement_adopter` FOREIGN KEY (`adopter_id`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_agreement_organization` FOREIGN KEY (`organization_id`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_agreement_pet` FOREIGN KEY (`pet_id`) REFERENCES `pet` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 15 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '领养协议表' ROW_FORMAT = DYNAMIC;

