DROP TABLE IF EXISTS `adoption_application`;
CREATE TABLE `adoption_application`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '申请ID',
  `pet_id` bigint NOT NULL COMMENT '宠物ID',
  `applicant_id` bigint NOT NULL COMMENT '申请人ID',
  `applicant_address` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '申请人地址（仅此字段user表无，协议留存用）',
  `family_members` int NULL DEFAULT NULL COMMENT '家庭成员数量',
  `housing_type` enum('apartment','house','farm','other') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '住房类型',
  `has_other_pets` tinyint(1) NULL DEFAULT 0 COMMENT '是否有其他宠物',
  `other_pets_info` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '其他宠物信息',
  `experience` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '养宠经验',
  `reason` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '领养理由',
  `status` enum('pending','approved','rejected','cancelled') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'pending',
  `reviewer_id` bigint NULL DEFAULT NULL COMMENT '审核人ID',
  `review_time` datetime NULL DEFAULT NULL COMMENT '审核时间',
  `review_comment` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '审核意见',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '申请时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_pet_applicant`(`pet_id` ASC, `applicant_id` ASC) USING BTREE,
  INDEX `idx_pet`(`pet_id` ASC) USING BTREE,
  INDEX `idx_applicant`(`applicant_id` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_pet_status`(`pet_id` ASC, `status` ASC) USING BTREE,
  INDEX `idx_applicant_status`(`applicant_id` ASC, `status` ASC) USING BTREE,
  INDEX `idx_reviewer`(`reviewer_id` ASC) USING BTREE,
  INDEX `idx_status_create`(`status` ASC, `create_time` DESC) USING BTREE,
  CONSTRAINT `adoption_application_ibfk_1` FOREIGN KEY (`pet_id`) REFERENCES `pet` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `adoption_application_ibfk_2` FOREIGN KEY (`applicant_id`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `adoption_application_ibfk_3` FOREIGN KEY (`reviewer_id`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 21 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '领养申请表' ROW_FORMAT = DYNAMIC;

