DROP TABLE IF EXISTS `pet_statistics`;
CREATE TABLE `pet_statistics`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `total_pets` int NULL DEFAULT 0 COMMENT '宠物总数',
  `available_pets` int NULL DEFAULT 0 COMMENT '可领养宠物数',
  `adopted_pets` int NULL DEFAULT 0 COMMENT '已领养宠物数',
  `pending_pets` int NULL DEFAULT 0 COMMENT '待审核宠物数',
  `pets_by_category` json NULL COMMENT '按分类统计',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '宠物统计表' ROW_FORMAT = Dynamic;

