-- ----------------------------
-- Table structure for post_adoption_tracking
-- ----------------------------
DROP TABLE IF EXISTS `post_adoption_tracking`;
CREATE TABLE `post_adoption_tracking`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `agreement_id` bigint NOT NULL COMMENT '协议ID',
  `tracking_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '跟踪类型',
  `tracking_date` datetime NOT NULL COMMENT '跟踪日期',
  `tracker_id` bigint NOT NULL COMMENT '跟踪员ID',
  `tracking_method` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '跟踪方式',
  `pet_health_status` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '宠物健康状态',
  `pet_behavior_status` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '宠物行为状态',
  `pet_weight` decimal(5, 2) NULL DEFAULT NULL COMMENT '宠物体重',
  `pet_photos` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '宠物照片',
  `living_environment` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '生活环境',
  `care_situation` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '照顾情况',
  `adopter_feedback` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '领养人反馈',
  `satisfaction_score` int NULL DEFAULT NULL COMMENT '满意度评分',
  `issues_found` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '发现的问题',
  `suggestions` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '建议',
  `next_tracking_date` datetime NULL DEFAULT NULL COMMENT '下次跟踪日期',
  `status` enum('scheduled','in_progress','completed','cancelled','overdue') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'scheduled' COMMENT '跟踪状态',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_agreement_id`(`agreement_id` ASC) USING BTREE,
  INDEX `idx_tracker_id`(`tracker_id` ASC) USING BTREE,
  INDEX `idx_tracking_type`(`tracking_type` ASC) USING BTREE,
  INDEX `idx_tracking_date`(`tracking_date` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_status_tracking_date`(`status` ASC, `tracking_date` ASC) USING BTREE,
  CONSTRAINT `post_adoption_tracking_ibfk_1` FOREIGN KEY (`agreement_id`) REFERENCES `adoption_agreement` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `post_adoption_tracking_ibfk_2` FOREIGN KEY (`tracker_id`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 17 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '领养后跟踪记录表' ROW_FORMAT = DYNAMIC;

