-- ----------------------------
-- View structure for v_agreement_detail
-- ----------------------------
DROP VIEW IF EXISTS `v_agreement_detail`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_agreement_detail` AS select `ag`.`id` AS `id`,`ag`.`agreement_number` AS `agreement_number`,`ag`.`pet_id` AS `pet_id`,`p`.`name` AS `pet_name`,`p`.`breed` AS `pet_breed`,`p`.`age` AS `pet_age`,`p`.`gender` AS `pet_gender`,`ag`.`adopter_id` AS `adopter_id`,`u_adopter`.`nickname` AS `adopter_name`,`u_adopter`.`phone` AS `adopter_phone`,`ag`.`adopter_id_card` AS `adopter_id_card`,`ag`.`adopter_address` AS `adopter_address`,`ag`.`organization_id` AS `organization_id`,`u_org`.`organization_name` AS `organization_name`,`u_org`.`phone` AS `organization_contact`,`u_org`.`organization_address` AS `organization_address`,`ag`.`adoption_fee` AS `adoption_fee`,`ag`.`agreement_content` AS `agreement_content`,`ag`.`status` AS `status`,`ag`.`sign_date` AS `sign_date`,`ag`.`effective_date` AS `effective_date`,`ag`.`expiry_date` AS `expiry_date`,`ag`.`adopter_signature` AS `adopter_signature`,`ag`.`organization_signature` AS `organization_signature`,`ag`.`admin_signature` AS `admin_signature`,`ag`.`create_time` AS `create_time`,`ag`.`update_time` AS `update_time`,(select count(0) from `tracking_plan` `tp` where (`tp`.`agreement_id` = `ag`.`id`)) AS `tracking_plan_count`,(select count(0) from `post_adoption_tracking` `pat` where (`pat`.`agreement_id` = `ag`.`id`)) AS `tracking_record_count` from (((`adoption_agreement` `ag` left join `pet` `p` on((`ag`.`pet_id` = `p`.`id`))) left join `user` `u_adopter` on((`ag`.`adopter_id` = `u_adopter`.`id`))) left join `user` `u_org` on((`ag`.`organization_id` = `u_org`.`id`)));

-- ----------------------------
-- View structure for v_application_detail
-- ----------------------------
DROP VIEW IF EXISTS `v_application_detail`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_application_detail` AS select `aa`.`id` AS `id`,`aa`.`pet_id` AS `pet_id`,`p`.`name` AS `pet_name`,`p`.`images` AS `pet_images`,`pc`.`name` AS `pet_category`,`aa`.`applicant_id` AS `applicant_id`,`u`.`username` AS `applicant_username`,`u`.`nickname` AS `applicant_nickname`,`u`.`nickname` AS `applicant_name`,`u`.`phone` AS `applicant_phone`,`u`.`email` AS `applicant_email`,`aa`.`applicant_address` AS `applicant_address`,`aa`.`family_members` AS `family_members`,`aa`.`housing_type` AS `housing_type`,`aa`.`has_other_pets` AS `has_other_pets`,`aa`.`other_pets_info` AS `other_pets_info`,`aa`.`experience` AS `experience`,`aa`.`reason` AS `reason`,`aa`.`status` AS `status`,`aa`.`reviewer_id` AS `reviewer_id`,`aa`.`review_time` AS `review_time`,`aa`.`review_comment` AS `review_comment`,`aa`.`create_time` AS `create_time`,`aa`.`update_time` AS `update_time`,`p`.`publisher_id` AS `organization_id` from (((`adoption_application` `aa` left join `pet` `p` on((`aa`.`pet_id` = `p`.`id`))) left join `pet_category` `pc` on((`p`.`category_id` = `pc`.`id`))) left join `user` `u` on((`aa`.`applicant_id` = `u`.`id`)));

-- ----------------------------
-- View structure for v_forum_post_detail
-- ----------------------------
DROP VIEW IF EXISTS `v_forum_post_detail`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_forum_post_detail` AS select `fp`.`id` AS `id`,`fp`.`title` AS `title`,`fp`.`content` AS `content`,`fp`.`author_id` AS `author_id`,`u`.`nickname` AS `author_name`,`u`.`avatar` AS `author_avatar`,`fp`.`images` AS `images`,`fp`.`pet_id` AS `pet_id`,`p`.`name` AS `pet_name`,(select count(0) from `forum_post_view_log` `v` where (`v`.`post_id` = `fp`.`id`)) AS `view_count`,(select count(0) from `forum_post_like` `fpl` where (`fpl`.`post_id` = `fp`.`id`)) AS `like_count`,(select count(0) from `forum_comment` `fc` where ((`fc`.`post_id` = `fp`.`id`) and (`fc`.`status` = 'published'))) AS `comment_count`,`fp`.`is_top` AS `is_top`,`fp`.`is_pinned` AS `is_pinned`,`fp`.`status` AS `status`,`fp`.`create_time` AS `create_time`,`fp`.`update_time` AS `update_time` from ((`forum_post` `fp` left join `user` `u` on((`fp`.`author_id` = `u`.`id`))) left join `pet` `p` on((`fp`.`pet_id` = `p`.`id`)));

-- ----------------------------
-- View structure for v_pet_detail
-- ----------------------------
DROP VIEW IF EXISTS `v_pet_detail`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_pet_detail` AS select `p`.`id` AS `id`,`p`.`name` AS `name`,`p`.`category_id` AS `category_id`,`pc`.`name` AS `category_name`,`p`.`breed` AS `breed`,`p`.`age` AS `age`,`p`.`gender` AS `gender`,`p`.`color` AS `color`,`p`.`size` AS `size`,`p`.`weight` AS `weight`,`p`.`description` AS `description`,`p`.`health_status` AS `health_status`,`p`.`vaccination` AS `vaccination`,`p`.`sterilization` AS `sterilization`,`p`.`images` AS `images`,`p`.`location` AS `location`,`p`.`contact_info` AS `contact_info`,`p`.`adoption_fee` AS `adoption_fee`,`p`.`status` AS `status`,`p`.`publisher_id` AS `publisher_id`,`u`.`username` AS `publisher_username`,`u`.`nickname` AS `publisher_nickname`,`u`.`organization_name` AS `publisher_org_name`,`p`.`create_time` AS `create_time`,`p`.`update_time` AS `update_time`,(select count(0) from `favorite` `f` where (`f`.`pet_id` = `p`.`id`)) AS `favorite_count`,(select count(0) from `adoption_application` `aa` where ((`aa`.`pet_id` = `p`.`id`) and (`aa`.`status` = 'pending'))) AS `pending_applications` from ((`pet` `p` left join `pet_category` `pc` on((`p`.`category_id` = `pc`.`id`))) left join `user` `u` on((`p`.`publisher_id` = `u`.`id`)));

-- ----------------------------
-- View structure for v_pet_statistics
-- ----------------------------
DROP VIEW IF EXISTS `v_pet_statistics`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_pet_statistics` AS select `p`.`id` AS `id`,`p`.`name` AS `name`,`p`.`status` AS `status`,(select count(0) from `favorite` `f` where (`f`.`pet_id` = `p`.`id`)) AS `favorite_count`,(select count(0) from `adoption_application` `aa` where ((`aa`.`pet_id` = `p`.`id`) and (`aa`.`status` in ('pending','approved')))) AS `apply_count`,(((coalesce((select count(0) from `user_behavior` `ub` where ((`ub`.`pet_id` = `p`.`id`) and (`ub`.`behavior_type` = 'VIEW'))),0) * 1.0) + ((select count(0) from `favorite` `f` where (`f`.`pet_id` = `p`.`id`)) * 5.0)) + ((select count(0) from `adoption_application` `aa` where ((`aa`.`pet_id` = `p`.`id`) and (`aa`.`status` in ('pending','approved')))) * 10.0)) AS `calculated_popularity` from `pet` `p`;

-- ----------------------------
-- View structure for v_pet_statistics_summary
-- ----------------------------
DROP VIEW IF EXISTS `v_pet_statistics_summary`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_pet_statistics_summary` AS select 1 AS `id`,(select count(0) from `pet`) AS `total_pets`,(select count(0) from `pet` where (`pet`.`status` = 'available')) AS `available_pets`,(select count(0) from `pet` where (`pet`.`status` = 'adopted')) AS `adopted_pets`,(select count(0) from `pet` where (`pet`.`status` = 'pending')) AS `pending_pets`,now() AS `update_time`;

-- ----------------------------
-- View structure for v_user_statistics
-- ----------------------------
DROP VIEW IF EXISTS `v_user_statistics`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_user_statistics` AS select `u`.`id` AS `id`,`u`.`username` AS `username`,`u`.`nickname` AS `nickname`,`u`.`role` AS `role`,60 AS `credit_score`,(select count(0) from `adoption_application` `aa` where ((`aa`.`applicant_id` = `u`.`id`) and (`aa`.`status` = 'approved'))) AS `success_adoption_count`,(select count(0) from `adoption_application` `aa` where (`aa`.`applicant_id` = `u`.`id`)) AS `total_application_count`,(select count(0) from `adoption_application` `aa` where ((`aa`.`applicant_id` = `u`.`id`) and (`aa`.`status` = 'cancelled'))) AS `cancel_application_count`,(select count(0) from `pet` where (`pet`.`publisher_id` = `u`.`id`)) AS `published_pets_count`,(select count(0) from `favorite` where (`favorite`.`user_id` = `u`.`id`)) AS `favorites_count`,(select count(0) from `message` where ((`message`.`receiver_id` = `u`.`id`) and (`message`.`is_read` = 0))) AS `unread_messages_count` from `user` `u`;

-- ----------------------------
-- Procedure structure for add_column_safe
-- ----------------------------
DROP PROCEDURE IF EXISTS `add_column_safe`;
delimiter ;;
CREATE PROCEDURE `add_column_safe`(IN p_table_name VARCHAR(64),
    IN p_column_name VARCHAR(64),
    IN p_column_definition TEXT)
BEGIN
    DECLARE column_exists INT DEFAULT 0;
    DECLARE CONTINUE HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            @sqlstate = RETURNED_SQLSTATE,
            @errno = MYSQL_ERRNO,
            @text = MESSAGE_TEXT;
        -- 忽略字段已存在的错误
        IF @errno = 1060 THEN
            SELECT CONCAT('Column already exists (ignored): ', p_table_name, '.', p_column_name) AS message;
        ELSE
            RESIGNAL;
        END IF;
    END;
    
    SELECT COUNT(*) INTO column_exists
    FROM INFORMATION_SCHEMA.COLUMNS
    WHERE TABLE_SCHEMA = DATABASE()
    AND TABLE_NAME = p_table_name
    AND COLUMN_NAME = p_column_name;
    
    IF column_exists = 0 THEN
        SET @sql = CONCAT('ALTER TABLE `', p_table_name, '` ADD COLUMN `', p_column_name, '` ', p_column_definition);
        PREPARE stmt FROM @sql;
        EXECUTE stmt;
        DEALLOCATE PREPARE stmt;
        SELECT CONCAT('Added column: ', p_table_name, '.', p_column_name) AS message;
    ELSE
        SELECT CONCAT('Column already exists: ', p_table_name, '.', p_column_name) AS message;
    END IF;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for add_index_safe
-- ----------------------------
DROP PROCEDURE IF EXISTS `add_index_safe`;
delimiter ;;
CREATE PROCEDURE `add_index_safe`(IN p_table_name VARCHAR(64),
    IN p_index_name VARCHAR(64),
    IN p_index_columns TEXT,
    IN p_is_unique BOOLEAN)
BEGIN
    DECLARE index_exists INT DEFAULT 0;
    DECLARE CONTINUE HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            @sqlstate = RETURNED_SQLSTATE,
            @errno = MYSQL_ERRNO,
            @text = MESSAGE_TEXT;
        -- 忽略索引已存在的错误
        IF @errno IN (1061, 1062) THEN
            SELECT CONCAT('Index already exists (ignored): ', p_table_name, '.', p_index_name) AS message;
        ELSE
            RESIGNAL;
        END IF;
    END;
    
    SELECT COUNT(*) INTO index_exists
    FROM INFORMATION_SCHEMA.STATISTICS
    WHERE TABLE_SCHEMA = DATABASE()
    AND TABLE_NAME = p_table_name
    AND INDEX_NAME = p_index_name;
    
    IF index_exists = 0 THEN
        IF p_is_unique THEN
            SET @sql = CONCAT('ALTER TABLE `', p_table_name, '` ADD UNIQUE INDEX `', p_index_name, '` (', p_index_columns, ')');
        ELSE
            SET @sql = CONCAT('ALTER TABLE `', p_table_name, '` ADD INDEX `', p_index_name, '` (', p_index_columns, ')');
        END IF;
        PREPARE stmt FROM @sql;
        EXECUTE stmt;
        DEALLOCATE PREPARE stmt;
        SELECT CONCAT('Added index: ', p_table_name, '.', p_index_name) AS message;
    ELSE
        SELECT CONCAT('Index already exists: ', p_table_name, '.', p_index_name) AS message;
    END IF;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for sp_add_column_safe
-- ----------------------------
DROP PROCEDURE IF EXISTS `sp_add_column_safe`;
delimiter ;;
CREATE PROCEDURE `sp_add_column_safe`(IN p_table VARCHAR(64),
    IN p_column VARCHAR(64),
    IN p_definition TEXT)
BEGIN
    DECLARE v_table_exists INT DEFAULT 0;
    DECLARE v_column_exists INT DEFAULT 0;
    
    SELECT COUNT(*) INTO v_table_exists
    FROM INFORMATION_SCHEMA.TABLES
    WHERE TABLE_SCHEMA = DATABASE()
    AND TABLE_NAME = p_table;
    
    IF v_table_exists = 0 THEN
        SELECT CONCAT('表不存在: ', p_table) AS message;
    ELSE
        SELECT COUNT(*) INTO v_column_exists
        FROM INFORMATION_SCHEMA.COLUMNS
        WHERE TABLE_SCHEMA = DATABASE()
        AND TABLE_NAME = p_table
        AND COLUMN_NAME = p_column;
        
        IF v_column_exists > 0 THEN
            SELECT CONCAT('字段已存在: ', p_table, '.', p_column) AS message;
        ELSE
            SET @sql = CONCAT('ALTER TABLE `', p_table, '` ADD COLUMN `', p_column, '` ', p_definition);
            PREPARE stmt FROM @sql;
            EXECUTE stmt;
            DEALLOCATE PREPARE stmt;
            SELECT CONCAT('✓ 已添加字段: ', p_table, '.', p_column) AS message;
        END IF;
    END IF;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for sp_add_index_safe
-- ----------------------------
DROP PROCEDURE IF EXISTS `sp_add_index_safe`;
delimiter ;;
CREATE PROCEDURE `sp_add_index_safe`(IN p_table VARCHAR(64),
    IN p_index VARCHAR(64),
    IN p_columns TEXT,
    IN p_unique BOOLEAN)
BEGIN
    DECLARE v_table_exists INT DEFAULT 0;
    DECLARE v_index_exists INT DEFAULT 0;
    
    SELECT COUNT(*) INTO v_table_exists
    FROM INFORMATION_SCHEMA.TABLES
    WHERE TABLE_SCHEMA = DATABASE()
    AND TABLE_NAME = p_table;
    
    IF v_table_exists = 0 THEN
        SELECT CONCAT('表不存在: ', p_table) AS message;
    ELSE
        SELECT COUNT(*) INTO v_index_exists
        FROM INFORMATION_SCHEMA.STATISTICS
        WHERE TABLE_SCHEMA = DATABASE()
        AND TABLE_NAME = p_table
        AND INDEX_NAME = p_index;
        
        IF v_index_exists > 0 THEN
            SELECT CONCAT('索引已存在: ', p_table, '.', p_index) AS message;
        ELSE
            IF p_unique THEN
                SET @sql = CONCAT('CREATE UNIQUE INDEX `', p_index, '` ON `', p_table, '` (', p_columns, ')');
            ELSE
                SET @sql = CONCAT('CREATE INDEX `', p_index, '` ON `', p_table, '` (', p_columns, ')');
            END IF;
            PREPARE stmt FROM @sql;
            EXECUTE stmt;
            DEALLOCATE PREPARE stmt;
            SELECT CONCAT('✓ 已添加索引: ', p_table, '.', p_index) AS message;
        END IF;
    END IF;
END
;;
delimiter ;

-- ----------------------------
-- Triggers structure for table adoption_application
-- ----------------------------
DROP TRIGGER IF EXISTS `check_duplicate_application`;
delimiter ;;
CREATE TRIGGER `check_duplicate_application` BEFORE INSERT ON `adoption_application` FOR EACH ROW BEGIN
    DECLARE existing_count INT DEFAULT 0;
    
    -- 检查是否已存在pending或approved状态的申请
    SELECT COUNT(*) INTO existing_count
    FROM `adoption_application`
    WHERE `pet_id` = NEW.`pet_id` 
      AND `applicant_id` = NEW.`applicant_id`
      AND `status` IN ('pending', 'approved')
      AND `id` != COALESCE(NEW.`id`, 0);  -- 排除当前记录（如果是更新操作）
    
    IF existing_count > 0 THEN
        SIGNAL SQLSTATE '45000' 
        SET MESSAGE_TEXT = '您已经申请过该宠物，请勿重复申请';
    END IF;
END
;;
delimiter ;

SET FOREIGN_KEY_CHECKS = 1;
